typeAliases.type:
| 'session'
  /** No live session — the placement mutates the scene-local game (single-player / stopped). */
  | 'local'

| 'retained'
  /** A fresh, non-retained presence publish seen while subscribed. Promotes the peer to live. */
  | 'live'
  /** An empty payload: a graceful leave or a fired Last-Will. Removes the peer entirely. */
  | 'absent'

| { readonly ok: true; readonly color: SeatColor; readonly seatMap: SeatMap }
  | {
      readonly ok: false;
      readonly reason: ClaimRejection;
      readonly seatMap: SeatMap;
    }

| { readonly action: 'adopt' }
  | { readonly action: 'ignore' }
  | { readonly action: 'conflict'; readonly divergePly: number }

properties:
readonly forks: {
    readonly mine: StoredLog;
    readonly theirs: StoredLog;
  }

typeAliases.type:
| { readonly kind: 'empty-node'; readonly node: NodeKey }
  | { readonly kind: 'placed-sphere'; readonly node: NodeKey }
  | { readonly kind: 'line'; readonly lineId: LineId }

methods:
setColors(next: { whitePiece?: string; blackPiece?: string }): {
    whitePiece: string;
    blackPiece: string;
  }

typeAliases.type:
| 'offline'
  /** A host/join is in flight (transport connecting / claiming a seat). */
  | 'connecting'
  /** In a room with a claimed seat: the connection/seat status line is shown. */
  | 'connected'
  /** The logs forked (GLOSSARY "Conflict"): the game is stopped and the conflict banner is shown. */
  | 'conflict'

| 'room-full'
  /** The transport could not connect (relay unreachable / rejected). */
  | 'connect-failed'

| 'empty'
  /** Fewer than {@link CODE_LENGTH} characters. */
  | 'too-short'
  /** Contains a character outside {@link CODE_ALPHABET} (after upper-casing). */
  | 'bad-chars'

| 'controls'
  /** Connection + seat status line (connecting / connected). */
  | 'status'
  /** The conflict banner (conflict). */
  | 'conflict'
